(1, 2, 'Trang Trại Xanh Hùng', 'Chuyên trồng rau sạch theo tiêu chuẩn VietGAP, hơn 10 năm kinh nghiệm. Cung cấp rau tươi mỗi ngày.', 'Long An', 'Cần Giuộc', NULL, 1, '2024-01-15 01:00:00', 4.80, 120, '2026-03-31 16:47:17', '2026-03-31 16:47:17'),
(2, 3, 'Vườn Rau Đà Lạt Mai', 'Vườn rau trên cao nguyên Đà Lạt 1.500m, khí hậu mát lành, rau ngọt tự nhiên không thuốc trừ sâu.', 'Lâm Đồng', 'Đà Lạt', NULL, 1, '2024-02-20 02:00:00', 4.90, 85, '2026-03-31 16:47:17', '2026-03-31 16:47:17'),
(3, 4, 'Miệt Vườn Bình An', 'Vùng đất An Giang phù sa màu mỡ, chuyên cung cấp trái cây miền Tây và lúa gạo đặc sản.', 'An Giang', 'Chợ Mới', NULL, 1, '2024-03-10 03:00:00', 4.70, 63, '2026-03-31 16:47:17', '2026-03-31 16:47:17'),
(4, 5, 'Trang Trại Cà Phê Hoa', 'Cà phê Robusta trồng tại Đắk Lắk, thu hoạch thủ công, rang mộc truyền thống.', 'Đắk Lắk', 'Cư Kuin', NULL, 1, '2026-05-01 04:11:32', 4.50, 28, '2026-03-31 16:47:17', '2026-05-01 04:11:32'),
(5, 13, 'Trang trại của tấn tai 47', NULL, NULL, NULL, NULL, 1, '2026-05-13 02:49:08', 0.00, 0, '2026-05-13 02:48:33', '2026-05-13 02:49:08');

