(1, 1, 1, 'Rau muống sạch VietGAP', 'rau-muong-sach-vietgap', 'Rau muống trồng theo tiêu chuẩn VietGAP, không dư lượng thuốc BVTV. Thu hoạch buổi sáng sớm, giao ngay trong ngày.', 15000, 'bó', 200, 20, '[\"data:image/jpeg;base64,\"]', 1, 850, 4.80, 95, '2026-03-31 16:47:17', '2026-05-01 04:05:12');
