(2, 1, 1, 'Cải xanh hữu cơ', 'cai-xanh-huu-co', 'Cải xanh trồng hữu cơ 100%, tưới nước sạch, không phân bón hóa học. Lá xanh mướt, giòn ngon.', 20000, 'kg', 150, 15, '[\"data:image/jpeg;base64,\"]', 1, 620, 4.75, 78, '2026-03-31 16:47:17', '2026-05-01 04:06:06');
