(3, 1, 1, 'Cà rốt Đà Lạt', 'ca-rot-da-lat-hung', 'Cà rốt nhập giống từ Đà Lạt, trồng tại Long An, củ to đều, ngọt giòn. Thích hợp ăn sống và nấu.', 25000, 'kg', 180, 20, '[\"data:image/jpeg;base64,\"]', 1, 410, 4.70, 55, '2026-03-31 16:47:17', '2026-05-01 04:05:31');
