-- Structure for view `v_hoa_don_chi_tiet`
--
DROP TABLE IF EXISTS `v_hoa_don_chi_tiet`;

DROP VIEW IF EXISTS `v_hoa_don_chi_tiet`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_hoa_don_chi_tiet`  AS SELECT `hd`.`ma_hoa_don` AS `ma_hoa_don`, `hd`.`so_hoa_don` AS `so_hoa_don`, `hd`.`loai_hoa_don` AS `loai_hoa_don`, `hd`.`ma_kho` AS `ma_kho`, `hd`.`ma_nong_dan` AS `ma_nong_dan`, `hd`.`ma_don_hang` AS `ma_don_hang`, `hd`.`nguoi_tao` AS `nguoi_tao`, `hd`.`tong_tien` AS `tong_tien`, `hd`.`ghi_chu` AS `ghi_chu`, `hd`.`trang_thai` AS `trang_thai`, `hd`.`ngay_xac_nhan` AS `ngay_xac_nhan`, `hd`.`ngay_tao` AS `ngay_tao`, `kh`.`ten_kho` AS `ten_kho`, `nd`.`ten_nong_trai` AS `ten_nong_dan`, `tk`.`ho_ten` AS `ten_nguoi_tao`, count(`cthd`.`ma_chi_tiet`) AS `so_dong` FROM ((((`hoa_don` `hd` join `kho_hang` `kh` on((`kh`.`ma_kho` = `hd`.`ma_kho`))) join `tai_khoan` `tk` on((`tk`.`ma_tai_khoan` = `hd`.`nguoi_tao`))) left join `nong_dan` `nd` on((`nd`.`ma_nong_dan` = `hd`.`ma_nong_dan`))) left join `chi_tiet_hoa_don` `cthd` on((`cthd`.`ma_hoa_don` = `hd`.`ma_hoa_don`))) GROUP BY `hd`.`ma_hoa_don` ;

