--
-- Structure for view `v_san_pham_nong_dan`
--
DROP TABLE IF EXISTS `v_san_pham_nong_dan`;

DROP VIEW IF EXISTS `v_san_pham_nong_dan`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_san_pham_nong_dan`  AS SELECT `sp`.`ma_san_pham` AS `ma_san_pham`, `sp`.`ma_nong_dan` AS `ma_nong_dan`, `sp`.`ma_danh_muc` AS `ma_danh_muc`, `sp`.`ten_san_pham` AS `ten_san_pham`, `sp`.`duong_dan` AS `duong_dan`, `sp`.`mo_ta` AS `mo_ta`, `sp`.`gia_ban` AS `gia_ban`, `sp`.`don_vi` AS `don_vi`, `sp`.`ton_kho` AS `ton_kho`, `sp`.`ton_kho_toi_thieu` AS `ton_kho_toi_thieu`, `sp`.`hinh_anh` AS `hinh_anh`, `sp`.`con_hoat_dong` AS `con_hoat_dong`, `sp`.`so_luong_ban` AS `so_luong_ban`, `sp`.`diem_danh_gia` AS `diem_danh_gia`, `sp`.`tong_danh_gia` AS `tong_danh_gia`, `sp`.`ngay_tao` AS `ngay_tao`, `sp`.`ngay_cap_nhat` AS `ngay_cap_nhat`, `nd`.`ten_nong_trai` AS `ten_nong_trai`, `nd`.`tinh_thanh` AS `tinh_thanh`, `nd`.`quan_huyen` AS `quan_huyen`, `nd`.`da_xac_minh` AS `nong_dan_xac_minh`, `tk`.`ho_ten` AS `ten_nong_dan`, `tk`.`anh_dai_dien` AS `anh_nong_dan` FROM ((`san_pham` `sp` join `nong_dan` `nd` on((`nd`.`ma_nong_dan` = `sp`.`ma_nong_dan`))) join `tai_khoan` `tk` on((`tk`.`ma_tai_khoan` = `nd`.`ma_tai_khoan`))) WHERE ((`sp`.`con_hoat_dong` = 1) AND (`tk`.`con_hoat_dong` = 1)) ;

