--
-- Structure for view `v_ton_kho_chi_tiet`
--
DROP TABLE IF EXISTS `v_ton_kho_chi_tiet`;

DROP VIEW IF EXISTS `v_ton_kho_chi_tiet`;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_ton_kho_chi_tiet`  AS SELECT `tk2`.`ma_kho` AS `ma_kho`, `kh`.`ten_kho` AS `ten_kho`, `tk2`.`ma_san_pham` AS `ma_san_pham`, `sp`.`ten_san_pham` AS `ten_san_pham`, `sp`.`don_vi` AS `don_vi`, `tk2`.`so_luong` AS `ton_hien_tai`, `sp`.`ton_kho_toi_thieu` AS `ton_kho_toi_thieu`, (case when (`tk2`.`so_luong` <= `sp`.`ton_kho_toi_thieu`) then 1 else 0 end) AS `can_nhap_them` FROM ((`ton_kho` `tk2` join `kho_hang` `kh` on((`kh`.`ma_kho` = `tk2`.`ma_kho`))) join `san_pham` `sp` on((`sp`.`ma_san_pham` = `tk2`.`ma_san_pham`))) ;
COMMIT;

